package com.company.supervision.api;import com.baomidou.mybatisplus.core.metadata.IPage;import com.company.supervision.application.ExecutionAppService;import com.company.supervision.entity.dto.*;import org.springframework.web.bind.annotation.*;@RestController @RequestMapping("/executions")public class ExecutionController{private final ExecutionAppService s;public ExecutionController(ExecutionAppService s){this.s=s;}@GetMapping public ApiResult<IPage<ExecutionSummary>>list(@RequestParam(required=false)Long taskId,@RequestParam(required=false)String status,@RequestParam(defaultValue="1")int page,@RequestParam(defaultValue="20")int size){return ApiResult.ok(s.listExecutions(taskId,status,page,size));}@GetMapping("/{id}")public ApiResult<ExecutionDetail>get(@PathVariable Long id){return ApiResult.ok(s.getExecution(id));}}
